#include <iostream>
#include <vector>

int find_nth_number(int n) {
    std::vector<int> sequence = {0, -1, -1};
    for (int i = 3; i <= n; ++i) {
        int next_number = sequence[i - 1] + sequence[i - 2] + sequence[i - 3];
        sequence.push_back(next_number);
    }
    return sequence[n];
}

int main() {
    int n;
    std::cout << "Enter the number for which you want to find the sequence number: ";
    std::cin >> n;
